import React, { useState } from 'react';

export default function Accordion({ items, allowMultiple = false }) {
  const [openIds, setOpenIds] = useState(() => new Set());

  const toggle = (id) => {
    setOpenIds((prev) => {
      const next = new Set(allowMultiple ? prev : []);
      if (prev.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  return (
    <div style={{ border: '1px solid #ddd', borderRadius: 8, overflow: 'hidden', maxWidth: 480 }}>
      {items.map((item) => {
        const isOpen = openIds.has(item.id);
        return (
          <div key={item.id} style={{ borderTop: '1px solid #eee' }}>
            <button
              onClick={() => toggle(item.id)}
              aria-expanded={isOpen}
              style={{
                width: '100%',
                textAlign: 'left',
                padding: '14px 16px',
                background: isOpen ? '#f5f7ff' : '#fff',
                border: 'none',
                cursor: 'pointer',
                fontSize: 16,
                fontWeight: 600,
                display: 'flex',
                justifyContent: 'space-between',
              }}
            >
              <span>{item.title}</span>
              <span style={{ transform: isOpen ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }}>⌄</span>
            </button>
            {isOpen && (
              <div style={{ padding: '0 16px 14px', color: '#444', lineHeight: 1.5 }}>{item.content}</div>
            )}
          </div>
        );
      })}
    </div>
  );
}

