import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface AccordionItem { id: string; title: string; content: string; }

@Component({
  selector: 'app-accordion',
  template: `
    <div style="border: 1px solid #ddd; border-radius: 8px; overflow: hidden; max-width: 480px;">
      <div *ngFor="let item of items" style="border-top: 1px solid #eee;">
        <button
          (click)="toggle(item.id)"
          [attr.aria-expanded]="isOpen(item.id)"
          [style.background]="isOpen(item.id) ? '#f5f7ff' : '#fff'"
          style="width: 100%; text-align: left; padding: 14px 16px; border: none; cursor: pointer; font-size: 16px; font-weight: 600; display: flex; justify-content: space-between;"
        >
          <span>{{ item.title }}</span>
          <span [style.transform]="isOpen(item.id) ? 'rotate(180deg)' : 'none'" style="transition: transform 0.2s;">⌄</span>
        </button>
        <div *ngIf="isOpen(item.id)" style="padding: 0 16px 14px; color: #444; line-height: 1.5;">{{ item.content }}</div>
      </div>
    </div>
  `,
})
export class AccordionComponent {
  @Input() items: AccordionItem[] = [];
  @Input() allowMultiple = false;
  private openIds = new Set<string>();

  isOpen(id: string): boolean {
    return this.openIds.has(id);
  }

  toggle(id: string): void {
    const wasOpen = this.openIds.has(id);
    if (!this.allowMultiple) {
      this.openIds.clear();
    }
    if (wasOpen) {
      this.openIds.delete(id);
    } else {
      this.openIds.add(id);
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Accordion Demo</h1>
      <app-accordion [items]="items" [allowMultiple]="false"></app-accordion>
    </div>
  `,
})
export class AppComponent {
  items: AccordionItem[] = [
    { id: 'a', title: 'What is an accordion?', content: 'A vertically stacked set of headers that each reveal a section of content.' },
    { id: 'b', title: 'When should I use one?', content: 'To condense long content into scannable, collapsible sections.' },
    { id: 'c', title: 'Single or multiple open?', content: 'Toggle the allowMultiple prop to permit more than one open panel.' },
  ];
}

@NgModule({
  declarations: [AppComponent, AccordionComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
